const sesion = $input.first().json;
const msg = $('On message').first().json;

const telegram_id = msg.message?.from?.id?.toString() 
  || msg.callback_query?.from?.id?.toString()
  || '';

const texto = msg.message?.text 
  || msg.callback_query?.data 
  || '';

const nombre = msg.message?.from?.first_name 
  || msg.callback_query?.from?.first_name 
  || 'Usuario';

let carrito = [];
try {
  carrito = sesion.CARRITO_TEMPORAL ? JSON.parse(sesion.CARRITO_TEMPORAL) : [];
} catch(e) {
  carrito = [];
}

return [{
  json: {
    telegram_id,
    nombre,
    texto,
    pantalla_actual: sesion.PANTALLA_ACTUAL || 'inicio',
    carrito,
    puntos_lealtad: 0,
    ULTIMO_CAPITULO: sesion.ULTIMO_CAPITULO || ''
  }
}];

const ctx = $input.first().json;

return [{
  json: {
    telegram_id: ctx.telegram_id,
    mensaje: 'Hola ' + ctx.nombre + '! Bienvenido a DeliveryBot\n\nQue quieres hacer?',
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Ver Menu', callback_data: 'ver_menu' }],
        [{ text: 'Mi Carrito', callback_data: 'ver_carrito' }],
        [{ text: 'Mis Pedidos', callback_data: 'mis_pedidos' }]
      ]
    })
  }
}];

const ctx = $input.first().json;
const carrito = ctx.carrito || [];

if (carrito.length === 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'Tu carrito esta vacio.',
      reply_markup: JSON.stringify({
        inline_keyboard: [
          [{ text: 'Ver Menu', callback_data: 'ver_menu' }],
          [{ text: 'Inicio', callback_data: '/start' }]
        ]
      })
    }
  }];
}

let detalle = carrito.map(item =>
  item.NOMBRE + ' x' + item.cantidad + ' = $' + item.subtotal.toLocaleString()
).join('\n');

const total = carrito.reduce((sum, item) => sum + item.subtotal, 0);

return [{
  json: {
    telegram_id: ctx.telegram_id,
    mensaje: 'Tu Carrito\n\n' + detalle + '\n\nTotal: $' + total.toLocaleString(),
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Confirmar Pedido', callback_data: 'confirmar_pedido' }],
        [{ text: 'Vaciar Carrito', callback_data: 'vaciar_carrito' }],
        [{ text: 'Seguir Comprando', callback_data: 'ver_menu' }]
      ]
    })
  }
}];

const ctx = $input.first().json;

return [{
  json: {
    telegram_id: ctx.telegram_id,
    mensaje: 'Menu Cafeteria\n\nElige una categoria:',
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Bebidas', callback_data: 'cat_Bebidas' }],
        [{ text: 'Comidas', callback_data: 'cat_Comidas' }],
        [{ text: 'Snacks', callback_data: 'cat_Snacks' }],
        [{ text: 'Volver', callback_data: '/start' }]
      ]
    })
  }
}];

const ctx = $('contexto').first().json;
const productos = $input.all();
const categoria = ctx.texto.replace('cat_', '');

if (!productos || productos.length === 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'No hay productos en ' + categoria + ' por el momento.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Volver al Menu', callback_data: 'ver_menu' }]]
      })
    }
  }];
}

const botones = productos.map(p => ([
  { text: p.json.NOMBRE + ' - $' + parseInt(p.json.PRECIO).toLocaleString() + ' (Stock: ' + p.json.STOCK + ')', callback_data: 'sel_' + p.json.ID_PRODUCTO }
]));

botones.push([{ text: 'Ver Carrito', callback_data: 'ver_carrito' }]);
botones.push([{ text: 'Volver al Menu', callback_data: 'ver_menu' }]);

return [{
  json: {
    telegram_id: ctx.telegram_id,
    mensaje: categoria + '\n\nElige un producto:',
    reply_markup: JSON.stringify({ inline_keyboard: botones })
  }
}];;

const ctx = $('procesar cantidad').first().json.texto ? $('procesar cantidad').first().json : $('recuperar contexto').first().json;
const producto = $input.first().json;

const partes = ctx.texto.split('_');
const cantidad = parseInt(partes[partes.length - 1]) || 1;

if (!producto || !producto.ID_PRODUCTO) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'Producto no encontrado.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Volver', callback_data: 'ver_menu' }]]
      })
    }
  }];
}

if (parseInt(producto.STOCK) <= 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: producto.NOMBRE + ' esta agotado.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Volver al Menu', callback_data: 'ver_menu' }]]
      })
    }
  }];
}

let carrito = ctx.carrito || [];
const idx = carrito.findIndex(item => item.ID_PRODUCTO === producto.ID_PRODUCTO);

if (idx >= 0) {
  carrito[idx].cantidad += cantidad;
  carrito[idx].subtotal = carrito[idx].cantidad * parseFloat(producto.PRECIO);
} else {
  carrito.push({
    ID_PRODUCTO: producto.ID_PRODUCTO,
    NOMBRE: producto.NOMBRE,
    PRECIO: parseFloat(producto.PRECIO),
    cantidad: cantidad,
    subtotal: parseFloat(producto.PRECIO) * cantidad
  });
}

const total = carrito.reduce((sum, item) => sum + item.subtotal, 0);

return [{
  json: {
    telegram_id: ctx.telegram_id,
    carrito_actualizado: carrito,
    mensaje: cantidad + ' x ' + producto.NOMBRE + ' agregado al carrito.\n\nTotal: $' + total.toLocaleString(),
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Ver Carrito', callback_data: 'ver_carrito' }],
        [{ text: 'Seguir Comprando', callback_data: 'ver_menu' }]
      ]
    })
  }
}];

const ctx = $input.first().json;
const carrito = ctx.carrito || [];

if (carrito.length === 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'No puedes confirmar un carrito vacio.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Ver Menu', callback_data: 'ver_menu' }]]
      })
    }
  }];
}

const subtotal = carrito.reduce((sum, item) => sum + item.subtotal, 0);
const puntos = parseInt(ctx.puntos_lealtad) || 0;

// Descuento por puntos
const descuento = puntos >= 100 ? Math.floor(puntos / 100) * 0.10 : 0;
const descuento_valor = Math.round(subtotal * descuento);

// IVA 19%
const base = subtotal - descuento_valor;
const iva = Math.round(base * 0.19);
const total = base + iva;

// Puntos ganados (1 punto por cada 1000 pesos)
const puntos_ganados = Math.floor(total / 1000);

const id_pedido = 'PED-' + Date.now();
const fecha = new Date().toLocaleDateString('es-CO');
const hora = new Date().toLocaleTimeString('es-CO');

let mensaje = 'Pedido Confirmado!\n\n';
mensaje += 'ID: ' + id_pedido + '\n';
mensaje += 'Subtotal: $' + subtotal.toLocaleString() + '\n';
if (descuento_valor > 0) {
  mensaje += 'Descuento (' + (descuento * 100) + '%): -$' + descuento_valor.toLocaleString() + '\n';
}
mensaje += 'IVA (19%): $' + iva.toLocaleString() + '\n';
mensaje += 'Total: $' + total.toLocaleString() + '\n';
mensaje += 'Puntos ganados: ' + puntos_ganados + '\n\n';
mensaje += 'Tu pedido esta siendo preparado.';

return [{
  json: {
    telegram_id: ctx.telegram_id,
    id_pedido,
    carrito,
    subtotal,
    descuento_valor,
    iva,
    total,
    puntos_ganados,
    puntos_actuales: puntos,
    fecha,
    hora,
    mensaje,
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Ver Mis Pedidos', callback_data: 'mis_pedidos' }],
        [{ text: 'Inicio', callback_data: '/start' }]
      ]
    })
  }
}];

const ctx = $input.first().json;

return [{
  json: {
    telegram_id: ctx.telegram_id,
    carrito_actualizado: [],
    mensaje: 'Carrito vaciado correctamente.',
    reply_markup: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Ver Menu', callback_data: 'ver_menu' }],
        [{ text: 'Inicio', callback_data: '/start' }]
      ]
    })
  }
}];

const items = $input.all();

for (const item of items) {
  if (item.json.telegram_id && item.json.mensaje) {
    return [{ json: item.json }];
  }
}

return [{ json: items[0]?.json || {} }];

const anterior = $('vaciar carrito').first().json;

return [{
  json: {
    telegram_id: anterior.telegram_id,
    mensaje: anterior.mensaje,
    reply_markup: anterior.reply_markup
  }
}];

const anterior = $('procesar pedido').first().json;

return [{
  json: {
    telegram_id: anterior.telegram_id,
    mensaje: anterior.mensaje,
    reply_markup: anterior.reply_markup
  }
}];

