const pedido = $('procesar pedido').first().json;
const carrito = pedido.carrito;

return carrito.map(item => ({
  json: {
    ID_PRODUCTO: item.ID_PRODUCTO,
    cantidad: item.cantidad,
    telegram_id: pedido.telegram_id,
    id_pedido: pedido.id_pedido,
    total: pedido.total,
    mensaje: pedido.mensaje,
    reply_markup: pedido.reply_markup
  }
}));

const stockItems = $input.all();
const carritoItems = $('extraer items pedidos').all();

return stockItems.map((stockItem, index) => {
  const carritoItem = carritoItems[index];
  const stockActual = parseInt(stockItem.json.STOCK);
  const cantidad = carritoItem ? carritoItem.json.cantidad : 1;

  return {
    json: {
      ID_PRODUCTO: stockItem.json.ID_PRODUCTO,
      stock_actual: stockActual,
      cantidad: cantidad,
      nuevo_stock: stockActual - cantidad
    }
  };
});

const ctx = $input.first().json;
const id_producto = ctx.texto.replace('sel_', '');

return [{
  json: {
    telegram_id: ctx.telegram_id,
    id_producto,
    carrito: ctx.carrito,
    nombre: ctx.nombre,
    puntos_lealtad: ctx.puntos_lealtad || 0,
    mensaje: 'Cuantas unidades quieres?\n\nEscribe un numero:',
    reply_markup: JSON.stringify({
      inline_keyboard: [[{ text: 'Cancelar', callback_data: 'ver_menu' }]]
    })
  }
}];

const ctx = $('contexto').first().json;
const usuario = $('buscar usuario').first().json;

return [{
  json: {
    ...ctx,
    puntos_lealtad: parseInt(usuario.PUNTOS_LEALTAD) || 0
  }
}];

const ctx = $input.first().json;
const cantidad = parseInt(ctx.texto);

if (isNaN(cantidad) || cantidad <= 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'Por favor escribe un numero valido.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Cancelar', callback_data: 'ver_menu' }]]
      })
    }
  }];
}

const id_producto = ctx.ULTIMO_CAPITULO || '';

return [{
  json: {
    telegram_id: ctx.telegram_id,
    texto: 'add_' + id_producto + '_' + cantidad,
    carrito: ctx.carrito,
    nombre: ctx.nombre,
    pantalla_actual: 'productos',
    puntos_lealtad: ctx.puntos_lealtad || 0
  }
}];

const anterior = $('preguntar cantidad').first().json;

return [{
  json: {
    telegram_id: anterior.telegram_id,
    mensaje: anterior.mensaje,
    reply_markup: anterior.reply_markup
  }
}];

const ctx = $input.first().json;
const carrito = ctx.carrito || [];

if (carrito.length === 0) {
  return [{
    json: {
      telegram_id: ctx.telegram_id,
      mensaje: 'Tu carrito esta vacio.',
      reply_markup: JSON.stringify({
        inline_keyboard: [[{ text: 'Ver Menu', callback_data: 'ver_menu' }]]
      }),
      stock_ok: false
    }
  }];
}

return [{
  json: {
    ...ctx,
    stock_ok: true
  }
}];
